const today = new Date();
const d7 = new Date(today.getTime() - 7*86400*1000);
const fmt = d => `${String(d.getDate()).padStart(2,'0')}-${String(d.getMonth()+1).padStart(2,'0')}-${d.getFullYear()}`;
return [{json: {fromDate: fmt(d7), toDate: fmt(today), isoFrom: d7.toISOString().slice(0,10), isoTo: today.toISOString().slice(0,10)}}];

const pageNodes = ['YM P1','YM P2','YM P3','YM P4','YM P5','YM P6','YM P7','YM P8'];
let allOrders = [];
let pagesFetched = 0;
let errors = [];
for (const p of pageNodes) {
  try {
    const arr = $(p).all();
    for (const it of arr) {
      const body = it.json || {};
      if (body && Array.isArray(body.orders) && body.orders.length > 0) {
        allOrders = allOrders.concat(body.orders);
        pagesFetched++;
      } else if (body && body.errors) {
        errors.push(p + ': ' + JSON.stringify(body.errors).slice(0,100));
      }
    }
  } catch(e) { errors.push(p + ': ' + e.message); }
}
const fromDate = $('Init Dates').item.json.isoFrom;
const toDate   = $('Init Dates').item.json.isoTo;
const seen = new Set(); const uniq = [];
for (const o of allOrders) { if (!seen.has(o.id)) { seen.add(o.id); uniq.push(o); } }
const skuStats = {};
for (const o of uniq) {
  const cancelled = (o.status === 'CANCELLED');
  for (const it of (o.items || [])) {
    const sku = it.offerId;
    if (!skuStats[sku]) skuStats[sku] = { total:0, cancelled:0, delivered:0, title: it.offerName || sku, prices: [] };
    skuStats[sku].total++;
    if (cancelled) skuStats[sku].cancelled++; else skuStats[sku].delivered++;
    skuStats[sku].prices.push(Number(it.buyerPrice) || 0);
  }
}
const problems = [];
for (const [sku, s] of Object.entries(skuStats)) {
  if (s.total >= 5 && (s.cancelled / s.total) >= 0.30) {
    const avgPrice = s.prices.length ? s.prices.reduce((a,b)=>a+b,0)/s.prices.length : 0;
    problems.push({ sku, title: s.title, cancelRate: s.cancelled/s.total, cancelled: s.cancelled, total: s.total, delivered: s.delivered, avgPrice });
  }
}
problems.sort((a,b) => b.cancelRate - a.cancelRate || b.total - a.total);
const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const period = fromDate + ' -> ' + toDate;
let text;
if (problems.length === 0) {
  text = '\u2705 <b>Problem SKUs Weekly</b>\n<i>' + period + '</i>\n\n\u0417\u0430 \u043d\u0435\u0434\u0435\u043b\u044e \u043d\u0435\u0442 SKU \u0441 \u22655 \u0437\u0430\u043a\u0430\u0437\u0430\u043c\u0438 \u0438 \u226530% \u043e\u0442\u043c\u0435\u043d.\n\n\u041e\u0431\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043e: ' + uniq.length + ' \u0437\u0430\u043a\u0430\u0437\u043e\u0432, ' + pagesFetched + ' \u0441\u0442\u0440\u0430\u043d\u0438\u0446 API.';
} else {
  const lines = problems.slice(0, 15).map(p =>
    '\u2022 <b>' + esc(p.sku) + '</b> \u2014 <b>' + Math.round(p.cancelRate*100) + '%</b> \u043e\u0442\u043c\u0435\u043d\u0430 (' + p.cancelled + '/' + p.total + ')\n  <i>' + esc((p.title||'').slice(0,90)) + '</i>\n  \u20bd' + Math.round(p.avgPrice) + ' \u0441\u0440.\u0446\u0435\u043d\u0430'
  ).join('\n\n');
  text = '\ud83d\udea8 <b>Problem SKUs Weekly</b>\n<i>' + period + '</i>\n\n\u041d\u0430\u0439\u0434\u0435\u043d\u043e ' + problems.length + ' SKU \u0441 \u22655 \u0437\u0430\u043a\u0430\u0437\u0430\u043c\u0438 \u0438 \u226530% \u043e\u0442\u043c\u0435\u043d:\n\n' + lines + '\n\n<i>\u0412\u0441\u0435\u0433\u043e \u043e\u0431\u0440\u0430\u0431\u043e\u0442\u0430\u043d\u043e: ' + uniq.length + ' \u0437\u0430\u043a\u0430\u0437\u043e\u0432, ' + pagesFetched + ' \u0441\u0442\u0440\u0430\u043d\u0438\u0446</i>\n\n\u2192 \u041c\u0430\u043a\u0441\u0438\u043c: \u043f\u0440\u043e\u0432\u0435\u0440\u044c \u044d\u0442\u0438 SKU \u0432 YM-\u043a\u0430\u0431\u0438\u043d\u0435\u0442\u0435, \u0434\u0435\u0430\u043a\u0442\u0438\u0432\u0438\u0440\u0443\u0439 \u0435\u0441\u043b\u0438 \u043a\u043b\u044e\u0447\u0438 \u043d\u0435\u0432\u0430\u043b\u0438\u0434\u043d\u044b\u0435 \u0438\u043b\u0438 \u0442\u043e\u0432\u0430\u0440\u044b region-locked.';
}
return [{json: {text, problems_count: problems.length, orders_analyzed: uniq.length, pages: pagesFetched, problems, errors}}];

// PG-нода возвращает одну строку с полем result = JSON массив
const input = $input.first().json || {};
let problems = input.result || [];
if (typeof problems === 'string') {
  try { problems = JSON.parse(problems); } catch(e) { problems = []; }
}
if (!Array.isArray(problems)) problems = [];

const esc = s => String(s||'').replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;');
const d7 = new Date(Date.now() - 7*86400*1000).toISOString().slice(0,10);
const d0 = new Date().toISOString().slice(0,10);
const period = d7 + ' \u2192 ' + d0;

let text;
if (problems.length === 0) {
  text = '\u2705 <b>Problem SKUs Weekly \u2014 \u0421\u0430\u0439\u0442</b>\n<i>' + period + '</i>\n\n\u0417\u0430 \u043d\u0435\u0434\u0435\u043b\u044e \u043d\u0435\u0442 \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 SKU \u0441 \u22655 \u0437\u0430\u043a\u0430\u0437\u0430\u043c\u0438 \u0438 \u226550% \u043e\u0442\u043c\u0435\u043d.';
} else {
  const lines = problems.slice(0, 12).map(p => {
    const stockStr = (p.stock_quantity >= 1000000) ? '\u221e' : String(p.stock_quantity);
    const price = (p.avg_price_eur != null) ? '\u20ac' + p.avg_price_eur : '';
    return '\u2022 <b>' + esc(p.sku) + '</b> \u2014 <b>' + Math.round(p.cancel_rate_pct) + '%</b> \u043e\u0442\u043c\u0435\u043d\u0430 (' + p.cancelled + '/' + p.total + ')\n  <i>' + esc((p.name||'').slice(0,85)) + '</i>\n  ' + esc((p.brand||'-').slice(0,25)) + ' | stock ' + stockStr + ' | ' + price;
  }).join('\n\n');
  text = '\ud83d\udea8 <b>Problem SKUs Weekly \u2014 \u0421\u0430\u0439\u0442</b>\n<i>' + period + '</i>\n\n\u041d\u0430\u0439\u0434\u0435\u043d\u043e ' + problems.length + ' \u0430\u043a\u0442\u0438\u0432\u043d\u044b\u0445 SKU \u0441 \u22655 \u0437\u0430\u043a\u0430\u0437\u0430\u043c\u0438 \u0438 \u226550% \u043e\u0442\u043c\u0435\u043d:\n\n' + lines + '\n\n\u2192 \u0421\u0430\u0448\u0430/\u041c\u0430\u043a\u0441\u0438\u043c: \u043f\u0440\u043e\u0432\u0435\u0440\u044c \u043f\u043e\u0441\u0442\u0430\u0432\u0449\u0438\u043a\u0430 \u0438\u043b\u0438 \u0432\u0440\u0435\u043c\u0435\u043d\u043d\u043e \u0434\u0435\u0430\u043a\u0442\u0438\u0432\u0438\u0440\u0443\u0439 (UPDATE products SET is_active=false WHERE ticker IN (...)).';
}

return [{ json: { text, problems_count: problems.length, problems } }];
